SELECT query, calls, mean_exec_time, max_exec_time, min_exec_time,
       rows, shared_blks_hit, shared_blks_read
FROM pg_stat_statements
WHERE calls >= {min_calls}
ORDER BY mean_exec_time DESC LIMIT {limit};

SELECT query, calls, mean_exec_time, max_exec_time, min_exec_time,
       total_exec_time, rows
FROM pg_stat_statements
WHERE mean_exec_time >= {threshold_ms}
ORDER BY mean_exec_time DESC LIMIT {limit};

SELECT schemaname, relname as table_name, n_live_tup, n_dead_tup,
       ROUND(n_dead_tup::numeric / NULLIF(n_live_tup + n_dead_tup, 0) * 100, 1) as dead_tuple_ratio,
       last_vacuum, last_autovacuum, vacuum_count, autovacuum_count
FROM pg_stat_user_tables
WHERE schemaname = 'public' AND n_dead_tup > {threshold}
ORDER BY n_dead_tup DESC;
